using System.Diagnostics;using ScraperBackendService.Core.Logging;namespace ScraperBackendService.Middleware;/// <summary>/// Memory monitoring and optimization middleware to prevent memory bloat./// Tracks memory usage and triggers garbage collection when needed./// </summary>public class MemoryOptimizationMiddleware{    private readonly RequestDelegate _next;    private readonly ILogger<MemoryOptimizationMiddleware> _logger;    private static long _requestCount = 0;    private static DateTime _lastGcTime = DateTime.UtcNow;    // Memory thresholds - Lower thresholds for more aggressive memory management    private const long HIGH_MEMORY_THRESHOLD = 800_000_000; // 800MB    private const long CRITICAL_MEMORY_THRESHOLD = 1_024_000_000; // 1GB    private const int GC_INTERVAL_REQUESTS = 100; // Force GC every 20 requests (reduced from 100)    private const int GC_INTERVAL_MINUTES = 5; // Force GC every 2 minutes (reduced from 5)    public MemoryOptimizationMiddleware(RequestDelegate next, ILogger<MemoryOptimizationMiddleware> logger)    {        _next = next;        _logger = logger;    }    public async Task InvokeAsync(HttpContext context)    {        var requestStart = Interlocked.Increment(ref _requestCount);        var memoryBefore = GC.GetTotalMemory(false);        try        {            await _next(context);            // Check memory usage after request            var memoryAfter = GC.GetTotalMemory(false);            var memoryDelta = memoryAfter - memoryBefore;            // Log significant memory increases (only for high increases to avoid log spam)            if (memoryDelta > 200_000_000) // 200MB increase per request            {                _logger.LogDebug("MemorySpike: High memory delta: {MemoryDelta}MB, Path: {Path}", memoryDelta / 1024 / 1024, context.Request.Path);            }            // Monitor total memory usage but avoid forcing GC to prevent blocking request processing            if (memoryAfter > CRITICAL_MEMORY_THRESHOLD && ShouldLogMemoryWarning())            {                 _logger.LogWarning("HighMemory: process memory at {MemoryMB}MB", memoryAfter / 1024 / 1024);            }        }        catch (Exception ex)        {            _logger.LogError(ex, "[MemoryMiddleware] Request failed: Path={Path}", context.Request.Path);            throw;        }    }    private bool ShouldLogMemoryWarning()    {         // Simple rate limiting for memory logs         if (DateTime.UtcNow - _lastGcTime > TimeSpan.FromMinutes(GC_INTERVAL_MINUTES))         {             _lastGcTime = DateTime.UtcNow;             return true;         }         return false;    }}